# ═══════════════════════════════════════════════════════════════════════════════
# BUILD FUNCTION — Called by persistent_agents.py and wipe_and_respawn.py
# ═══════════════════════════════════════════════════════════════════════════════

def build_agent_prompt(name: str, role_title: str, focus: str, dept_id: str, dept_name: str) -> str:
    """
    Assemble a 3-layer system prompt for a marketplace agent.
    
    Args:
        name: Agent's display name (e.g., "Elena Vasquez")
        role_title: Specific role (e.g., "Memecoin/Crypto Trader")
        focus: Role focus description from agent_departments.py
        dept_id: Department key (e.g., "finance_trading")
        dept_name: Department display name (e.g., "Finance & Trading")
    
    Returns:
        Complete system prompt string (typically 2000-4000 chars)
    """
    # Layer 1: Professional base
    base = PROFESSIONAL_BASE.format(
        name=name,
        role_title=role_title,
        dept_name=dept_name,
    )
    
    # Layer 2: Department framework
    dept = DEPT_FRAMEWORKS.get(dept_id, "")
    
    # Layer 3: Role-specific instructions
    role_key = f"{dept_id}::{role_title}"
    if role_key in ROLE_INSTRUCTIONS:
        role = ROLE_INSTRUCTIONS[role_key]
    else:
        role = DEFAULT_ROLE_INSTRUCTION.format(
            role_title=role_title,
            focus=focus,
        )
    
    # Assemble final prompt
    prompt = f"{base}\n{dept}\n{role}"
    
    return prompt.strip()
